namespace sv_8617c6bea0204ec6a6bf924b799d02c2.Services;

public class CartItem
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public decimal Price { get; set; }
    public int Quantity { get; set; }
}

public class CartState
{
    private readonly List<CartItem> _items = new();

    public IReadOnlyList<CartItem> Items => _items.AsReadOnly();

    public int TotalCount => _items.Sum(i => i.Quantity);

    public decimal TotalPrice => _items.Sum(i => i.Price * i.Quantity);

    public event Action? OnChange;

    public void Add(int id, string name, decimal price)
    {
        var existing = _items.FirstOrDefault(i => i.Id == id);
        if (existing is not null)
        {
            existing.Quantity++;
        }
        else
        {
            _items.Add(new CartItem { Id = id, Name = name, Price = price, Quantity = 1 });
        }
        NotifyStateChanged();
    }

    public void Remove(int id)
    {
        var item = _items.FirstOrDefault(i => i.Id == id);
        if (item is not null)
        {
            _items.Remove(item);
            NotifyStateChanged();
        }
    }

    public void Clear()
    {
        _items.Clear();
        NotifyStateChanged();
    }

    private void NotifyStateChanged() => OnChange?.Invoke();
}

@using sv_8617c6bea0204ec6a6bf924b799d02c2.Services
@inject CartState Cart
@implements IDisposable

<a href="cart" class="nav-link" style="position: relative; display: inline-block;">
    <span class="bi bi-cart-nav-menu" aria-hidden="true"></span> Cart
    @if (Cart.TotalCount > 0)
    {
        <span class="badge bg-danger rounded-pill" style="position: absolute; top: -2px; right: -10px; font-size: 0.7rem;">
            @Cart.TotalCount
        </span>
    }
</a>

@code {
    protected override void OnInitialized()
    {
        Cart.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        Cart.OnChange -= StateHasChanged;
    }
}

@page "/products"
@using sv_8617c6bea0204ec6a6bf924b799d02c2.Services
@inject CartState Cart
@rendermode InteractiveServer

<PageTitle>Products</PageTitle>

<h1>Products</h1>

<div class="row row-cols-1 row-cols-md-3 g-4 mt-2">
    @foreach (var product in _products)
    {
        <div class="col">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@product.Name</h5>
                    <p class="card-text text-muted">@product.Description</p>
                    <p class="card-text fw-bold">@product.Price.ToString("C")</p>
                </div>
                <div class="card-footer">
                    <button class="btn btn-primary" @onclick="() => AddToCart(product)">
                        Add to Cart
                    </button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private readonly List<ProductInfo> _products = new()
    {
        new(1, "Wireless Mouse", "Ergonomic wireless mouse with USB receiver.", 29.99m),
        new(2, "Mechanical Keyboard", "RGB backlit mechanical keyboard with blue switches.", 79.99m),
        new(3, "USB-C Hub", "7-in-1 USB-C hub with HDMI, USB 3.0, and SD card reader.", 49.99m),
        new(4, "Monitor Stand", "Adjustable aluminum monitor stand with cable management.", 39.99m),
        new(5, "Webcam HD", "1080p HD webcam with built-in microphone.", 59.99m),
        new(6, "Laptop Sleeve", "Water-resistant neoprene laptop sleeve for 15-inch laptops.", 19.99m),
    };

    private void AddToCart(ProductInfo product)
    {
        Cart.Add(product.Id, product.Name, product.Price);
    }

    private record ProductInfo(int Id, string Name, string Description, decimal Price);
}

